  1	import * as React from 'react';
  2	import { IRow, ISortBy, OnSort, SortByDirection, TableVariant } from '@patternfly/react-table';
  3	import { ZtunnelWorkload } from '../../types/IstioObjects';
  4	import { EmptyState, EmptyStateBody, EmptyStateVariant } from '@patternfly/react-core';
  5	import { emtpytStyle } from './ZtunnelServicesTable';
  6	import { SimpleTable } from '../Table/SimpleTable';
  7	import { t } from 'i18next';
  8	import { SortableCompareTh, stickyThead, yoverflow } from './ZtunnelConfig';
  9	
 10	type ZtunnelWorkloadsProps = {
 11	  config?: ZtunnelWorkload[];
 12	};
 13	
 14	const columns: SortableCompareTh<ZtunnelWorkload>[] = [
 15	  {
 16	    title: t('Namespace'),
 17	    sortable: true,
 18	    compare: (a, b) => a.namespace.localeCompare(b.namespace)
 19	  },
 20	  {
 21	    title: t('Pod Name'),
 22	    sortable: true,
 23	    compare: (a, b) => a.name.localeCompare(b.name)
 24	  },
 25	  {
 26	    title: t('Address'),
 27	    sortable: false
 28	  },
 29	  {
 30	    title: t('Node'),
 31	    sortable: true,
 32	    compare: (a, b) => a.node.localeCompare(b.node)
 33	  },
 34	  {
 35	    title: t('Waypoint'),
 36	    sortable: false
 37	  },
 38	  {
 39	    title: t('Protocol'),
 40	    sortable: false
 41	  }
 42	];
 43	
 44	export const ZtunnelWorkloadsTable: React.FC<ZtunnelWorkloadsProps> = (props: ZtunnelWorkloadsProps) => {
 45	  const [sortBy, setSortBy] = React.useState(0);
 46	  const [sortDirection, setSortDirection] = React.useState(SortByDirection.asc);
 47	
 48	  const compare = columns[sortBy].compare;
 49	  const sorted = compare
 50	    ? props.config?.sort(sortDirection === SortByDirection.asc ? compare : (a, b) => compare(b, a))
 51	    : props.config;
 52	
 53	  const sort: ISortBy = { index: sortBy, direction: sortDirection };
 54	  const onSort: OnSort = (_event: React.MouseEvent, index: number, sortDirection: SortByDirection) => {
 55	    setSortBy(index);
 56	    setSortDirection(sortDirection);
 57	  };
 58	
 59	  const rows: IRow[] = sorted
 60	    ? sorted.map(workload => {
 61	        return {
 62	          cells: [
 63	            workload.namespace,
 64	            workload.name,
 65	            workload.workloadIps.map(ip => {
 66	              return ip;
 67	            }),
 68	            workload.node,
 69	            workload.waypoint ? (
 70	              <>
 71	                {workload.waypoint.destination}:{workload.waypoint.hboneMtlsPort}
 72	              </>
 73	            ) : (
 74	              t('None')
 75	            ),
 76	            workload.protocol
 77	          ]
 78	        };
 79	      })
 80	    : [];
 81	
 82	  const noWorkloadsConfig: React.ReactNode = (
 83	    <EmptyState variant={EmptyStateVariant.sm} className={emtpytStyle}>
 84	      <EmptyStateBody className={emtpytStyle} data-test="istio-config-empty">
 85	        {t('No Ztunnel workloads found')}
 86	      </EmptyStateBody>
 87	    </EmptyState>
 88	  );
 89	
 90	  return (
 91	    <div className={yoverflow}>
 92	      <SimpleTable
 93	        label={t('Ztunnel workloads config')}
 94	        columns={columns}
 95	        rows={rows}
 96	        variant={TableVariant.compact}
 97	        emptyState={noWorkloadsConfig}
 98	        sortBy={sort}
 99	        onSort={onSort}
100	        theadStyle={stickyThead}
101	      />
102	    </div>
103	  );
104	};

